// ---- cross-device sign in (username + PIN against the online account) ----
function showSignin(){ $('regView').style.display='none'; $('loginView').style.display='none';
  $('signinView').style.display=''; $('siErr').textContent=''; }
$('toSignin').onclick=showSignin;
$('siToReg').onclick=showReg;
if($('goSignin2')) $('goSignin2').onclick=showSignin;
async function signInOnline(){
  const u=$('siUser').value.trim(), pin=$('siPin').value.trim(), e=$('siErr');
  if(u.length<3||pin.length<4){ e.textContent='Enter your username and 4-digit PIN.'; return; }
  if(!sb){ e.textContent='Online sign-in unavailable right now.'; return; }
  e.textContent='Signing in…';
  await resetOnlineSession();           // drop any previous account's online session first
  const email=u.toLowerCase()+'@trenchmon.app', password='pin_'+pin;
  const r=await sb.auth.signInWithPassword({email,password});
  if(r.error){ e.textContent='No account found with those details.'; return; }
  const uid=r.data.user.id;
  // pull their own profile (wallet readable because it's their row)
  const { data:prof } = await sb.from('profiles').select('username,wallet,avatar,wins,losses,xp,coins').eq('id',uid).single();
  const uname=(prof&&prof.username)||u;
  sbUser={id:uid, username:uname};
  // mirror into a local account so the rest of the game works offline too
  const accts=accounts();
  accts[uname.toLowerCase()]={username:uname, addr:(prof&&prof.wallet)||'', pin,
    wins:(prof&&prof.wins)||0, losses:(prof&&prof.losses)||0, xp:(prof&&prof.xp)||0,
    coins:(prof&&prof.coins!=null)?prof.coins:1000, friends:[]};
  saveAccts(accts); DB.set('sh_last', uname); account=accts[uname.toLowerCase()];
  if(prof&&prof.avatar) DB.set('sh_pic_'+uname.toLowerCase(), prof.avatar);
  startPresence(); startInbox(); enterLobby();
}
$('siBtn').onclick=signInOnline;
$('siPin').addEventListener('input',e=>{ e.target.value=e.target.value.replace(/\D/g,'').slice(0,4); });
$('siPin').addEventListener('keydown',e=>{ if(e.key==='Enter') signInOnline(); });

// ---- Profile screen ----
function openProfile(){
  hideAllOverlays();
  $('profileScreen').classList.remove('hide');
  $('profUser').textContent=account.username;
  $('profAddr').textContent=shortAddr(account.addr);
  $('profilePic').src=avatarOf(account.username);
  const a=accounts()[account.username.toLowerCase()]||account;
  const lv=levelFromXp(a.xp||0); const pct=Math.round(lv.into/lv.need*100);
  $('profUser').innerHTML=account.username+' <span class="lvlchip">Lv'+lv.level+'</span>';
  $('profWins').textContent=a.wins||0; $('profLoss').textContent=a.losses||0;
  const tot=(a.wins||0)+(a.losses||0);
  $('profRate').textContent= tot? Math.round((a.wins||0)/tot*100)+'%' : '—';
  $('profCoinsTop').innerHTML= coinIcon()+(account.guest ? ' —' : (' '+(a.coins||0)));
  showProfTab('stats');
  $('profComments').innerHTML='<div class="empty">—</div>';
  (async()=>{ if(SOCIAL_ON()){ if(!sbUser) await ensureOnline(); if(sbUser){ loadComments(sbUser.id, $('profComments')); syncCoins(); } } })();
}
function showProfTab(t){
  $('tabStats').style.display = t==='stats'?'block':'none';
  $('tabAch').style.display = t==='ach'?'block':'none';
  if(t==='ach') renderAchievements();
}
seg('profTabs','data-tab',showProfTab);

// ---- viewing ANOTHER player's profile (avatar, record, comments) ----
let pubTarget=null, pubBackFn=null;
async function loadComments(profileId, el){
  el.innerHTML='<div class="empty">Loading…</div>';
  if(!sb){ el.innerHTML='<div class="empty">—</div>'; return; }
  const { data } = await sb.rpc('comments_for',{p_profile:profileId, p_limit:50});
  if(!data || !data.length){ el.innerHTML='<div class="empty">No comments yet.</div>'; return; }
  el.innerHTML='';
  data.forEach(c=>{ const d=document.createElement('div'); d.className='cmt';
    d.innerHTML='<div class="ca" data-prof="'+c.author_name+'"></div><div class="cb"></div>';
    d.querySelector('.ca').textContent=c.author_name; d.querySelector('.cb').textContent=c.body;
    el.appendChild(d); });
  el.querySelectorAll('[data-prof]').forEach(b=> b.onclick=()=> openPubProfile(b.getAttribute('data-prof')) );
}
async function openPubProfile(username, back){
  if(!username) return;
  if(account && username.toLowerCase()===account.username.toLowerCase()){ openProfile(); return; }
  pubBackFn = back || (()=>{ $('startScreen').classList.remove('hide'); refreshAcctBtn(); });
  hideAllOverlays(); $('pubProfileScreen').classList.remove('hide');
  $('pubName').textContent=username; $('pubPic').src=''; $('pubRec').textContent='…';
  $('pubAddBtn').style.display='none'; $('pubAddBtn').textContent='➕ ADD FRIEND'; $('pubAddBtn').classList.remove('disabled');
  $('pubComments').innerHTML='<div class="empty">Loading…</div>';
  if(!sb){ $('pubRec').textContent='offline'; return; }
  if(!sbUser) await ensureOnline();
  const { data } = await sb.rpc('public_profile',{p_username:username});
  if(!data || !data.length){ $('pubRec').textContent='no online profile'; $('pubComments').innerHTML='<div class="empty">This player has no online profile yet.</div>'; return; }
  const p=data[0]; pubTarget={id:p.id, username:p.username};
  const plv=levelFromXp(p.xp||0).level;
  $('pubName').innerHTML=p.username+' <span class="lvlchip">Lv'+plv+'</span>';
  $('pubPic').src=p.avatar||'';
  $('pubRec').textContent=(p.wins||0)+'W · '+(p.losses||0)+'L';
  $('pubAddBtn').style.display = friendSet.has(p.username.toLowerCase()) ? 'none' : 'block';
  loadComments(p.id, $('pubComments'));
}
async function postPubComment(){
  const t=$('pubCommentInput').value.trim(); if(!t || !pubTarget) return;
  if(!sbUser){ if(!await ensureOnline()) return; }
  $('pubCommentInput').value='';
  await sb.from('comments').insert({profile_id:pubTarget.id, author_id:sbUser.id, author_name:sbUser.username, body:t});
  notifyUser(pubTarget.id, 'comment', {fromName:sbUser.username});   // ping the profile owner
  bumpStat('comments');
  loadComments(pubTarget.id, $('pubComments'));
}
$('pubBackBtn').onclick=()=>{ $('pubProfileScreen').classList.add('hide'); if(pubBackFn) pubBackFn(); };
$('pubAddBtn').onclick=()=>{ if(pubTarget){ addFriend(pubTarget.username); $('pubAddBtn').textContent='REQUEST SENT'; $('pubAddBtn').classList.add('disabled'); } };
$('pubCommentBtn').onclick=postPubComment;
$('pubCommentInput').addEventListener('keydown',e=>{ if(e.key==='Enter') postPubComment(); });
$('acctBtn').onclick=openProfile;
$('profileBackBtn').onclick=()=>{ $('profileScreen').classList.add('hide'); $('startScreen').classList.remove('hide'); };
$('profSwitchBtn').onclick=logout;

// ---- profile picture upload (downscaled, saved locally + to your online profile) ----
$('changePicBtn').onclick=()=>$('picInput').click();
$('picInput').onchange=e=>{
  const f=e.target.files[0]; if(!f) return;
  const r=new FileReader();
  r.onload=()=>{ const img=new Image(); img.onload=()=>{
    const c=document.createElement('canvas'); c.width=c.height=96;
    const cx=c.getContext('2d'); const sz=Math.min(img.width,img.height);
    cx.drawImage(img,(img.width-sz)/2,(img.height-sz)/2,sz,sz,0,0,96,96);
    const data=c.toDataURL('image/jpeg',0.8);
    DB.set('sh_pic_'+account.username.toLowerCase(), data);
    $('profilePic').src=data; refreshAcctBtn();
    if(sbUser){ sb.from('profiles').update({avatar:data}).eq('id',sbUser.id); }  // show on leaderboard
    bumpStat('pic');
  }; img.src=r.result; };
  r.readAsDataURL(f);
};

// ---- notifications / inbox ----
let inboxChan=null, notifyChan=null, freqChan=null, unread={}, cnotes=[], freqs=[];
function readsMap(){ return DB.get('sh_reads_'+(sbUser?sbUser.id:''))||{}; }
function markRead(senderId){ if(!sbUser)return; const r=readsMap(); r[senderId]=Date.now(); DB.set('sh_reads_'+sbUser.id,r);
  delete unread[senderId]; DB.set('sh_unread_'+sbUser.id,unread); bellRefresh(); }
function bellRefresh(){
  const n=Object.values(unread).filter(Boolean).length + cnotes.length + freqs.length;
  const b=$('bellCount'); if(n>0){ b.textContent=n; b.classList.remove('hide'); } else b.classList.add('hide');
}
// pull anything missed while the app was closed (messages + friend requests)
async function refreshServerNotifs(){
  if(!sbUser) return;
  try{
    const { data } = await sb.from('messages').select('sender,created_at')
      .eq('recipient',sbUser.id).order('created_at',{ascending:false}).limit(100);
    const reads=readsMap(), latest={};
    (data||[]).forEach(m=>{ if(!latest[m.sender]) latest[m.sender]=m.created_at; });
    Object.keys(latest).forEach(sid=>{ if(new Date(latest[sid]).getTime() > (reads[sid]||0)) unread[sid]=true; });
    DB.set('sh_unread_'+sbUser.id,unread);
  }catch(e){}
  try{ const { data } = await sb.rpc('my_friends');
    freqs=(data||[]).filter(f=>f.incoming).map(f=>({id:f.friend_id, name:f.username})); }catch(e){}
  bellRefresh();
}
async function startInbox(){
  if(!sbUser) return;
  unread=DB.get('sh_unread_'+sbUser.id)||{};
  cnotes=DB.get('sh_cnotes_'+sbUser.id)||[];
  bellRefresh(); startNotify();
  await refreshServerNotifs();
  if(!inboxChan){
    inboxChan=sb.channel('inbox:'+sbUser.id)
      .on('postgres_changes',{event:'INSERT',schema:'public',table:'messages',filter:'recipient=eq.'+sbUser.id},
        payload=>{ const m=payload.new;
          if(!(chatPeer && chatPeer.id===m.sender)){ unread[m.sender]=true;
            DB.set('sh_unread_'+sbUser.id,unread); bellRefresh(); showToast('💬 new message','#9bf6a8'); }
        }).subscribe();
  }
  if(!freqChan){
    freqChan=sb.channel('freq:'+sbUser.id)
      .on('postgres_changes',{event:'INSERT',schema:'public',table:'friendships',filter:'addressee=eq.'+sbUser.id},
        ()=>{ refreshServerNotifs(); showToast('🤝 new friend request','#9bf6a8');
          if(!$('socialScreen').classList.contains('hide')) renderFriends(); })
      .on('postgres_changes',{event:'UPDATE',schema:'public',table:'friendships',filter:'requester=eq.'+sbUser.id},
        ()=>{ if(!$('socialScreen').classList.contains('hide')) renderFriends(); })
      .subscribe();
  }
}
// per-user realtime channel for challenges + comment notifications
function startNotify(){
  if(notifyChan || !sbUser) return;
  notifyChan=sb.channel('notify:'+sbUser.id, {config:{broadcast:{self:false}}})
    .on('broadcast',{event:'challenge'},     ({payload})=> onChallenge(payload))
    .on('broadcast',{event:'challenge_resp'},({payload})=> onChallengeResp(payload))
    .on('broadcast',{event:'comment'},       ({payload})=> onCommentNotify(payload))
    .subscribe();
}
// send a one-off broadcast to another user's notify channel
async function notifyUser(userId, event, payload){
  if(!sb) return;
  const ch=sb.channel('notify:'+userId, {config:{broadcast:{self:true}}});
  await new Promise(res=>{ let done=false; ch.subscribe(s=>{ if(s==='SUBSCRIBED'&&!done){done=true;res();} }); setTimeout(res,1500); });
  await ch.send({type:'broadcast', event, payload});
  setTimeout(()=>{ try{sb.removeChannel(ch);}catch(e){} }, 1500);
}
function onCommentNotify(p){
  cnotes.unshift({name:(p&&p.fromName)||'someone', ts:Date.now()}); cnotes=cnotes.slice(0,10);
  DB.set('sh_cnotes_'+sbUser.id,cnotes); bellRefresh();
  showToast('📝 '+((p&&p.fromName)||'Someone')+' commented on your profile','#9bf6a8');
}
function closeInbox(){ $('inboxScreen').classList.add('hide'); }
async function openInbox(){
  if(!$('inboxScreen').classList.contains('hide')){ closeInbox(); return; }
  $('inboxScreen').classList.remove('hide');
  const list=$('inboxList'); list.innerHTML='<div class="empty">Loading…</div>';
  if(!sbUser){ if(!await ensureOnline()){ list.innerHTML='<div class="empty">Open Social once to sign in.</div>'; return; } }
  await refreshServerNotifs();
  list.innerHTML='';
  // 1) friend requests
  freqs.forEach(fr=>{ const row=document.createElement('div'); row.className='frow'; row.style.cursor='pointer';
    row.innerHTML='<span class="fmeta"><span class="cdot online"></span><span class="fn">🤝 '+fr.name+'</span></span>'
      +'<span class="muted" style="margin:0">sent a friend request</span>';
    row.onclick=()=>{ closeInbox(); openSocial(); };
    list.appendChild(row); });
  // 2) comment notifications
  cnotes.forEach(c=>{ const row=document.createElement('div'); row.className='frow'; row.style.cursor='pointer';
    row.innerHTML='<span class="fmeta"><span class="cdot online"></span><span class="fn">📝 '+c.name+'</span></span>'
      +'<span class="muted" style="margin:0">commented on your profile</span>';
    row.onclick=()=>{ cnotes=[]; DB.set('sh_cnotes_'+sbUser.id,cnotes); bellRefresh(); closeInbox(); openProfile(); };
    list.appendChild(row); });
  // 3) unread text messages
  const unreadIds=Object.keys(unread).filter(k=>unread[k]);
  if(!unreadIds.length && !cnotes.length && !freqs.length){ list.innerHTML='<div class="empty">No new notifications.</div>'; return; }
  if(unreadIds.length){
    const { data } = await sb.from('messages').select('sender,body,created_at')
      .eq('recipient',sbUser.id).in('sender',unreadIds).order('created_at',{ascending:false}).limit(50);
    const seen=new Set(), rows=[];
    (data||[]).forEach(m=>{ if(seen.has(m.sender))return; seen.add(m.sender); rows.push({other:m.sender,last:m.body}); });
    const { data:profs } = await sb.rpc('names_for',{ids:unreadIds});
    const nameOf={}; (profs||[]).forEach(p=>nameOf[p.id]=p.username);
    rows.forEach(r=>{ const row=document.createElement('div'); row.className='frow'; row.style.cursor='pointer';
      row.innerHTML='<span class="fmeta"><span class="cdot online"></span><span class="fn">'+(nameOf[r.other]||'player')+'</span></span>'
        +'<span class="muted" style="margin:0;max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+r.last+'</span>';
      row.onclick=()=>{ markRead(r.other); closeInbox(); openChat(r.other, nameOf[r.other]||'player'); };
      list.appendChild(row); });
  }
}
$('bellBtn').onclick=openInbox;

// ---- challenge a friend (real-time invite) ----
let challengeTarget=null, incomingChallenge=null, chTimer=null;
async function challengeFriend(friendId, name){
  const wss=DB.get('sh_lobby')||$('netUrl').value.trim()||DEFAULT_LOBBY;
  if(!/^wss?:\/\//.test(wss)){ alert('Open "Play a Friend" and connect once so your lobby URL is saved, then you can challenge friends.'); return; }
  if(!sbUser){ if(!await ensureOnline()) return; }
  challengeTarget={id:friendId, name};
  hideAllOverlays(); $('onlineScreen').classList.remove('hide');
  $('netUrl').value=wss; $('lobbyBox').classList.add('hide'); $('netErr').textContent='';
  $('netStatus').textContent='Creating a lobby to challenge '+name+'…';
  audioInit(); NET.connect(()=>NET.create());
}
function onChallenge(p){
  if(!p || state==='play') return;                 // ignore mid-match
  incomingChallenge=p;
  $('chFrom').textContent=p.fromName||'Someone';
  const pop=$('challengePopup'); pop.classList.remove('hide');
  // restart the 15s countdown bar
  const bar=$('chBarFill'); bar.style.animation='none'; void bar.offsetWidth; bar.style.animation='chCountdown 15s linear forwards';
  if(chTimer) clearTimeout(chTimer);
  chTimer=setTimeout(()=>{ dismissChallenge(); }, 15000);
}
function dismissChallenge(){ $('challengePopup').classList.add('hide'); incomingChallenge=null; if(chTimer){clearTimeout(chTimer);chTimer=null;} }
function acceptChallenge(){
  const p=incomingChallenge; if(!p) return; dismissChallenge();
  pendingJoin={ code:p.code, s:p.wss }; autoJoin();
}
function declineChallenge(){
  const p=incomingChallenge; if(!p) return; dismissChallenge();
  if(p.fromId) notifyUser(p.fromId, 'challenge_resp', {accepted:false, fromName:(sbUser?sbUser.username:'They')});
}
function onChallengeResp(p){
  if(p && p.accepted===false){
    showToast('❌ '+((p&&p.fromName)||'They')+' declined your challenge','#ff8787');
    challengeTarget=null;
    if(NET.ws){ try{NET.send({t:'leave'});NET.ws.close();}catch(e){} }
    netRole=null; hideAllOverlays(); $('startScreen').classList.remove('hide'); setMenuDocks(true); refreshAcctBtn();
  }
}
$('chAccept').onclick=acceptChallenge;
$('chDecline').onclick=declineChallenge;

// only ever show one full-screen interface at a time
function hideAllOverlays(){
  setMenuDocks(false);   // daily tab + server picker only belong on the home screen (re-enabled by enterLobby/gotoMenu)
  document.querySelectorAll('.overlay').forEach(o=>o.classList.add('hide'));
  closeInbox();
}

// ---- Quick Match (online-style; no server -> ranked vs CPU) ----
function startQuickMatch(){
  audioInit();
  if(!account){ showAuth(); return; }
  // humanChar + gameMode were chosen on the select screen
  $('startScreen').classList.add('hide'); $('selectScreen').classList.add('hide'); $('matchScreen').classList.remove('hide');
  $('meName').textContent=account.username; $('oppName').textContent='…';
  $('matchStatus').textContent='Searching for opponents'; $('matchNote').textContent='Finding a live opponent…';
  quickMode=true; quickStruggle=false;
  let dots=0; matchTimer=setInterval(()=>{ dots=(dots+1)%4;
    $('matchStatus').textContent=(quickStruggle?'Still searching':'Searching for opponents')+'.'.repeat(dots); }, 350);
  $('netUrl').value = DB.get('sh_lobby')||DEFAULT_LOBBY;     // use the saved (Sydney) relay
  NET.connect(()=>{ if(quickMode) NET.send({t:'quick'}); });  // queue once connected
  // keep searching — after 30s just let them know it's quiet (don't drop to CPU)
  quickTimer=setTimeout(()=>{ if(quickMode){ quickStruggle=true;
    $('matchNote').textContent='Struggling to find players on this server — still searching. Invite a mate, or tap Cancel.'; } }, 30000);
}
function cancelMatch(){ quickMode=false; clearInterval(matchTimer); clearTimeout(quickTimer);
  try{ NET.intentionalClose=true; NET.send({t:'cancel'}); }catch(_){}
  try{ if(NET.ws) NET.ws.close(); }catch(_){}
  netRole=null;
  $('matchScreen').classList.add('hide'); $('startScreen').classList.remove('hide'); setMenuDocks(true); }
