// ====== ONLINE LOBBY (play a friend, real-time, host-authoritative) ======
let netRole=null, netKickPrev=false, stateSendAcc=0, gInputAcc=0, pingAcc=0, pingDispAcc=0, gp=null;
// active match wager ($BASED). matchId is a value BOTH peers agree on (lobby code + host nonce).
let wager={amount:0, oppId:null, matchId:null, settled:false};
// how this online match was set up: 'quick' (guest picked its own stake -> use min of both)
// vs 'friend' (guest accepts the host's stake). Set when matched/joined, not via csContext,
// so a stale select-screen context can't leak the wrong rule in.
let onlineKind='friend';
function resetWager(){ wager={amount:0, oppId:null, matchId:null, settled:false}; updatePotTag(); }
function updatePotTag(){ const el=$('potTag'); if(!el) return;
  if(wager.amount>0){ el.innerHTML=coinIcon()+' POT '+(wager.amount*2)+' $BASED'; el.classList.remove('hide'); }
  else el.classList.add('hide'); }
function gpInit(){ gp = players? {x:players.t.x,y:players.t.y,vx:0,vy:0} : {x:W*0.73,y:H/2,vx:0,vy:0}; }
function predictGuestSelf(){
  if(!gp) gpInit();
  let ax=0,ay=0;
  if(keys['w'])ay-=1; if(keys['s'])ay+=1; if(keys['a'])ax-=1; if(keys['d'])ax+=1;
  if(joyActive){ax+=joyVec.x;ay+=joyVec.y;}
  const m=Math.hypot(ax,ay); if(m>1){ax/=m;ay/=m;}
  const t=players.t;
  // mirror applyMove on the host: no sprint on empty stamina, and the same 1.25 accel ramp,
  // so the prediction doesn't run faster than the authoritative sim and get yanked back.
  const sprint=(keys['shiftleft']||keys['shift']||touchSprint) && (t.stamina!=null ? t.stamina>0.02 : true) && m>0.1;
  const ACC=sprint?1.25:1.0;
  const gbase=(ball.owner==='t')?t.maxOn:t.maxOff;               // mirror the host's on/off split for our own player
  let MAX=gbase*(sprint?SPRINT_MULT:1);
  if(ball.owner && ball.owner!=='t') MAX+=DEF_CLOSE_BONUS*(t.defense||5);        // and the closing-speed bonus
  if(gameMode==='keepaway'&&ball.owner==='t') MAX*=0.75;
  gp.vx+=ax*ACC; gp.vy+=ay*ACC;
  const sp=Math.hypot(gp.vx,gp.vy); if(sp>MAX){gp.vx=gp.vx/sp*MAX; gp.vy=gp.vy/sp*MAX;}
  gp.vx*=0.84; gp.vy*=0.84; gp.x+=gp.vx; gp.y+=gp.vy;
  confineRound(gp,PLAYER_R);
  // Reconcile against the FRESHEST authoritative position (not the interpolation-delayed
  // one) so there's no constant backward pull. Ease gently when close; firm up only when
  // drifting; hard-snap on big jumps (kickoffs / goal resets) so they don't rubber-band.
  const auth = NET.state && NET.state.t;
  if(auth){
    const ex=auth.x-gp.x, ey=auth.y-gp.y, err=Math.hypot(ex,ey);
    if(err>200){ gp.x=auth.x; gp.y=auth.y; gp.vx=0; gp.vy=0; }   // only hard-snap on a real desync (goal reset)
    else { const k = err>60 ? 0.16 : 0.05; gp.x+=ex*k; gp.y+=ey*k; }
  }
  t.x=gp.x; t.y=gp.y;
  // aim arrow: on touch follow the joystick (no mouse exists — this was the frozen "halfway" arrow);
  // hold the last heading when the stick is centred. Desktop keeps mouse aim.
  if(IS_TOUCH){ if(joyActive && (joyVec.x||joyVec.y)) guestAim=Math.atan2(joyVec.y,joyVec.x); t.aim=guestAim; }
  else t.aim=Math.atan2(mouse.y-t.y, mouse.x-t.x);
  if(Math.abs(gp.vx)>0.3) t.face=gp.vx>0?1:-1;
  // predict our own charge bar locally so it fills instantly while we hold
  const held=!!(keys['kick']||touchKick);
  if(held){ t.charging=true; t.charge=Math.min(1, (t.charge||0)+(1/(CHARGE_TIME*60))); }
  else { t.charging=false; t.charge=0; }
}
const NET = {
  ws:null, role:null, intentionalClose:false, reconnTries:0,
  connect(then){
    const url=$('netUrl').value.trim();
    if(!/^wss?:\/\//.test(url)){ $('netErr').textContent='Enter your lobby URL (wss://…).'; return; }
    DB.set('sh_lobby', url);
    $('netErr').textContent=''; $('netStatus').textContent='Connecting…';
    try{ this.ws=new WebSocket(url); }catch(e){ $('netErr').textContent='Could not connect.'; return; }
    this.ws.onopen=()=>{ $('netStatus').textContent='Connected to lobby.'; then&&then(); };
    this.ws.onmessage=ev=>{ let m; try{m=JSON.parse(ev.data);}catch{return;} handleNet(m); };
    this.ws.onclose=()=>this.handleClose();
    this.ws.onerror=()=>{ $('netErr').textContent='Connection error — check the URL.'; };
  },
  // a drop mid-match no longer instantly forfeits — try to rejoin the same room first
  handleClose(){
    if(this.intentionalClose){ this.intentionalClose=false; return; }
    if(state==='play' && netRole && this.code){
      if(this.reconnTries>=5){ onPeerGone('Could not reconnect.'); return; }
      this.reconnTries++;
      showToast('📶 Reconnecting… ('+this.reconnTries+'/5)','#ffd43b');
      const d=Math.min(500*this.reconnTries, 2500);
      setTimeout(()=>{ if(state!=='play') return;
        this.connect(()=>this.send({t:'rejoin', code:this.code, role:netRole})); }, d);
      return;
    }
    onPeerGone('Connection closed.');
  },
  send(o){ if(this.ws&&this.ws.readyState===1) this.ws.send(JSON.stringify(o)); },
  relay(d){
    // Only the loss-tolerant, high-rate game traffic (snapshots/input/ping) takes the direct P2P
    // data channel — that skips the Sydney relay hop and ~halves the round-trip. One-time control
    // messages (start/hello/wagerAck/rematch/left) MUST be reliable, so they always use the WS.
    if(this.dc && this.dc.readyState==='open' && (d.state||d.input||d.ping!=null||d.pong!=null)){
      try{ this.dc.send(JSON.stringify(d)); return; }catch(e){}
    }
    this.send({t:'relay', d});
  },
  // ---- WebRTC P2P: an optional accelerator layered on top; the WS relay is always the fallback ----
  dc:null, pc:null, p2p:false, remoteSet:false, candQ:[],
  signal(rtc){ this.send({t:'relay', d:{rtc}}); },          // signalling always rides the WS relay
  p2pStart(initiator){
    if(typeof RTCPeerConnection==='undefined' || this.pc) return;   // unsupported, or already negotiating
    let pc; try{ pc=new RTCPeerConnection({iceServers:[
      {urls:'stun:stun.l.google.com:19302'},{urls:'stun:stun1.l.google.com:19302'}]}); }catch(e){ return; }
    this.pc=pc; this.remoteSet=false; this.candQ=[];
    pc.onicecandidate=e=>{ if(e.candidate) this.signal({c:e.candidate}); };
    pc.onconnectionstatechange=()=>{ const s=pc.connectionState; if(s==='failed'||s==='disconnected') this.p2pDown(); };
    const wire=dc=>{ this.dc=dc;
      dc.onopen=()=>{ this.p2p=true; NET.rtt=null; showToast('⚡ Direct P2P connected — lower ping','#69db7c'); };
      dc.onclose=()=>this.p2pDown();
      dc.onmessage=ev=>{ let d; try{d=JSON.parse(ev.data);}catch(_){return;} onRelayData(d); };
    };
    if(initiator){ wire(pc.createDataChannel('game',{ordered:false,maxRetransmits:0}));
      pc.createOffer().then(o=>pc.setLocalDescription(o)).then(()=>this.signal({o:pc.localDescription})).catch(()=>{}); }
    else { pc.ondatachannel=e=>wire(e.channel); }
    setTimeout(()=>{ if(!this.p2p && this.pc===pc){ try{pc.close();}catch(_){}}}, 10000);   // 10s to connect, else stay on relay
  },
  p2pHandle(rtc){
    if(!this.pc){ if(rtc.o) this.p2pStart(false); else return; }   // offer arrived first → spin up as the answerer
    const pc=this.pc;
    if(rtc.o){ pc.setRemoteDescription(rtc.o).then(()=>{ this.remoteSet=true; this.drainCand(); return pc.createAnswer(); })
        .then(a=>pc.setLocalDescription(a)).then(()=>this.signal({a:pc.localDescription})).catch(()=>{}); }
    else if(rtc.a){ pc.setRemoteDescription(rtc.a).then(()=>{ this.remoteSet=true; this.drainCand(); }).catch(()=>{}); }
    else if(rtc.c){ if(this.remoteSet) pc.addIceCandidate(rtc.c).catch(()=>{}); else this.candQ.push(rtc.c); }
  },
  drainCand(){ for(const c of this.candQ){ try{ this.pc.addIceCandidate(c).catch(()=>{}); }catch(_){} } this.candQ=[]; },
  p2pDown(){ if(this.dc){ try{this.dc.close();}catch(_){}} this.dc=null;
    if(this.p2p){ this.p2p=false; showToast('Relay mode','#ffd43b'); } },   // game keeps running on the WS relay
  p2pReset(){ this.p2pDown(); if(this.pc){ try{this.pc.close();}catch(_){}} this.pc=null; this.remoteSet=false; this.candQ=[]; this.p2p=false; },
  state:null, buf:[],
  guestInput:{ax:0,ay:0,aim:Math.PI,sprint:false,kick:false}
};
function handleNet(m){
  if(m.t==='created'){ $('lobbyBox').classList.remove('hide'); $('lobbyCode').textContent=m.code;
    NET.code=m.code; onlineKind='friend';
    const link=buildInvite(m.code); $('inviteUrl').value=link;       // show the full link right away
    try{ navigator.clipboard.writeText(link); $('inviteHint').textContent='Invite link copied — paste it to your friend.'; }catch(e){}
    $('netStatus').textContent='Waiting for your friend to join…'; netRole='host';
    if(challengeTarget && sbUser){      // this lobby was opened to challenge a friend -> ping them
      const wss=DB.get('sh_lobby')||$('netUrl').value.trim()||DEFAULT_LOBBY;
      notifyUser(challengeTarget.id, 'challenge', {fromId:sbUser.id, fromName:sbUser.username, code:m.code, wss});
      $('netStatus').textContent='Challenge sent to '+challengeTarget.name+' — waiting for them to accept…';
    } }
  else if(m.t==='joined'){ $('netStatus').textContent='Joined! Waiting for host to start…'; netRole='guest'; onlineKind='friend'; }
  else if(m.t==='searching'){ if($('matchStatus')) $('matchStatus').textContent='Searching for opponents'; }
  else if(m.t==='matched'){
    quickMode=false; clearTimeout(quickTimer); clearInterval(matchTimer); onlineKind='quick';
    NET.code=m.code; netRole=m.role;
    NET.p2pStart(m.role==='host');          // start direct-connection negotiation (host offers)
    if(account) NET.relay({hello:{name:account.username}});
    $('oppName').textContent='opponent'; $('matchStatus').textContent='Opponent found! Starting…';
    if(m.role==='host'){
      sendHostStart();
      $('matchScreen').classList.add('hide'); beginGameOnline('host');
    }
    // guest: beginGameOnline('guest') fires when the host's d.start arrives (also hides matchScreen)
  }
  else if(m.t==='peer-here'){ $('netStatus').textContent='Connected! Waiting for host to start…';
    NET.p2pStart(false);                    // guest: be ready to answer the host's offer
    if(account) NET.relay({hello:{name:account.username}}); }
  else if(m.t==='peer-joined'){ $('netStatus').textContent='Friend connected! Choose your character…';
    NET.p2pStart(true);                      // host: offer a direct connection while we pick characters
    setTimeout(()=>openSelect('host'), 600); }
  else if(m.t==='error'){ if(NET.reconnTries>0){ NET.reconnTries=0; onPeerGone('Match ended.'); } else $('netErr').textContent=m.msg||'Lobby error.'; }
  else if(m.t==='resumed'){ NET.reconnTries=0; showToast('✅ Reconnected!','#69db7c'); }        // we rejoined the room
  else if(m.t==='peer-dropped'){ showToast('📶 Opponent reconnecting…','#ffd43b'); }            // they dropped — wait, don't forfeit
  else if(m.t==='peer-back'){ showToast('✅ Opponent reconnected!','#69db7c'); }                 // they came back
  else if(m.t==='peer-left'){ onPeerGone('Your friend disconnected.'); }
  else if(m.t==='relay'){ onRelayData(m.d||{}); }
}
// relay payloads arrive over the WebSocket OR — once connected — the direct peer-to-peer
// data channel. Both call this so the handling is identical regardless of transport.
function onRelayData(d){
    if(d.rtc){ NET.p2pHandle(d.rtc); return; }     // WebRTC signalling rides the relay channel
    if(d.hello){ NET.peerName=d.hello.name; }
    else if(d.start){ humanChar=d.start.hostChar; NET.peerName=d.start.hostName||NET.peerName; gameMode=d.start.mode||'goals';
      setupGuestWager(d.start); beginGameOnline('guest'); }
    else if(d.wagerAck){                                  // host learns the guest's id, stake + character
      if(d.wagerAck.char){ oppChar=d.wagerAck.char;       // guest's chosen character (may equal host's)
        if(netRole==='host' && players && players.t && players.t.char!==oppChar){   // ack arrived after reset() -> fix avatar+stats+labels
          const t=players.t; players.t=mkPlayer(t.x,t.y,'t',oppChar);
          players.t.vx=t.vx; players.t.vy=t.vy; players.t.aim=t.aim; players.t.face=t.face; players.t.stamina=t.stamina;
          const tc=$('tCard').querySelector('.pc-name'); if(tc) tc.textContent=(NET.peerName||STATS[oppChar].name);
          $('tTeam').textContent=STATS[oppChar].abbr; } }
      let amount=d.wagerAck.amount||0; const oppId=d.wagerAck.guestId||null;
      const intended = onlineWagerEnabled() && stakeSel>0;
      if(!onlineWagerEnabled() || !sbUser || !oppId || amount>myCoins()) amount=0;
      wager.oppId=oppId; wager.amount=amount;
      if(intended && !oppId && !amount) showToast('🎮 Opponent is a guest — casual match','#9bf6a8');  // only when it changes their expectation
      updatePotTag(); }
    else if(d.input){ NET.guestInput=d.input; }        // host receives guest input
    else if(d.state){ pushNetState(d.state); }          // guest buffers snapshot for smoothing
    else if(d.rematch){ onPeerRematch(); }              // friend tapped REMATCH
    else if(d.left){ peerLeft=true; greyRematch('Your friend went back to the menu.'); }
    else if(d.ping!=null){ NET.relay({pong:d.ping}); }   // bounce it back so the peer can measure RTT
    else if(d.pong!=null){ const rtt=Math.round(performance.now()-d.pong);
      // asymmetric EMA: grow the cushion FAST on a spike, relax it slowly — so a ping
      // jump expands the buffer within ~1s instead of stuttering for several seconds.
      NET.rtt = NET.rtt==null ? rtt : (rtt>NET.rtt ? Math.round(NET.rtt*0.4+rtt*0.6) : Math.round(NET.rtt*0.85+rtt*0.15));
      INTERP_DELAY = clamp(34 + NET.rtt*0.30, 44, 140);   // low floor for AU-AU/P2P; EMA still grows it fast on jitter
      BALL_DELAY   = clamp(16 + NET.rtt*0.10, 20, 54); }   // ball near real-time — kicks land almost instantly on low ping
}
// remember the last few real people you played online
function recordOpponent(name){
  if(!name) return;
  let r=DB.get('sh_recentOpps')||[];
  r=r.filter(x=>x.toLowerCase()!==name.toLowerCase()); r.unshift(name); r=r.slice(0,3);
  DB.set('sh_recentOpps', r);
}
function onPeerGone(msg){
  if(netRole && state==='play'){ showToast(msg,'#ffd43b'); }
  $('netStatus').textContent=msg;
  if(state==='win'){ peerLeft=true; greyRematch('Your friend disconnected.'); }
  if(state==='play'){ setTimeout(()=>{ netRole=null; gotoMenu(); }, 1200); }
  netRole = netRole && state!=='play' ? null : netRole;
}
