async function pingServer(r){
  const base='https://basedcup-lobby-'+r+'.fly.dev/';
  try{
    // Warm the connection FIRST (DNS + TCP + TLS) so we time the network round-trip, not the
    // one-off handshake — that handshake was inflating the displayed ping ~2-3x (e.g. 40ms link
    // reading as 120ms). Then take the FASTEST of a few keep-alive reuses to filter jitter.
    await fetch(base+'?w='+Date.now(),{mode:'no-cors',cache:'no-store',keepalive:true});
    let best=Infinity;
    for(let i=0;i<3;i++){ const t0=performance.now();
      await fetch(base+'?p='+Date.now()+'_'+i,{mode:'no-cors',cache:'no-store',keepalive:true});
      best=Math.min(best, performance.now()-t0); }
    return best===Infinity?null:Math.round(best);
  }catch(e){ return null; }
}
function pingClass(p){ return p==null?'pbad':p<90?'pgood':p<200?'pmid':'pbad'; }
async function refreshServerPopup(){
  document.querySelectorAll('#serverPopup .spRow').forEach(row=>{
    const r=row.getAttribute('data-region'), el=row.querySelector('.spMeta'); if(!el) return;
    const players=playersOnRegion(r);
    el.innerHTML='ping&nbsp;…<br>'+(players==null?'—':players)+'&nbsp;playing';
    pingServer(r).then(p=>{ el.innerHTML='<span class="'+pingClass(p)+'">'+(p==null?'offline':('ping '+p+'ms'))+'</span><br>'+
      (players==null?'—':players)+'&nbsp;playing'; });
  });
}
