// ---- Leaderboard (online when hosted; local accounts otherwise) ----
function renderLocalBoard(){
  const all=Object.values(accounts()).sort((a,b)=> b.wins-a.wins || a.losses-b.losses);
  const list=$('boardList'); list.innerHTML='';
  if(!all.length){ list.innerHTML='<div class="empty">No accounts yet.</div>'; }
  let myRank=0;
  all.forEach((p,i)=>{ const me=account&&p.username.toLowerCase()===account.username.toLowerCase(); if(me)myRank=i+1;
    const row=document.createElement('div'); row.className='brow'+(me?' me':'');
    row.innerHTML='<span class="rk">'+(i+1)+'</span><span class="bn">'+p.username+'</span><span class="bw">'+p.wins+'W · '+p.losses+'L</span>';
    list.appendChild(row); });
  $('yourRank').textContent = myRank? ('Your rank: #'+myRank+' of '+all.length) : '';
}
async function openBoard(){
  hideAllOverlays(); $('boardScreen').classList.remove('hide');
  const list=$('boardList'); $('yourRank').textContent='';
  if(LB.on()){
    list.innerHTML='<div class="empty">Loading…</div>';
    const data=await LB.board(12,20);
    if(data && data.leaderboard){
      list.innerHTML='';
      if(!data.leaderboard.length) list.innerHTML='<div class="empty">No ranked wins in the last 12h yet.</div>';
      // fetch profile pictures for the shown players (usernames only — no wallets exposed)
      let avaMap={};
      if(sb && data.leaderboard.length){
        try{ const names=data.leaderboard.map(p=>p.username);
          const {data:avs}=await sb.rpc('avatars_for',{p_names:names});
          (avs||[]).forEach(a=>{ if(a.avatar) avaMap[a.username.toLowerCase()]=a.avatar; });
        }catch(e){}
      }
      data.leaderboard.forEach(p=>{ const me=account&&p.username.toLowerCase()===account.username.toLowerCase();
        const av=avaMap[p.username.toLowerCase()]||avatarOf(p.username);
        const row=document.createElement('div'); row.className='brow'+(me?' me':'');
        row.innerHTML='<span class="rk">'+p.rank+'</span>'
          +(av?'<img class="ava" src="'+av+'">':'<span class="ava"></span>')
          +'<span class="bn" data-prof="'+p.username+'">'+p.username+'</span><span class="bw">'+p.wins+'W · '+p.losses+'L</span>';
        list.appendChild(row); });
      list.querySelectorAll('[data-prof]').forEach(b=>{ b.style.cursor='pointer';
        b.onclick=()=> openPubProfile(b.getAttribute('data-prof'), openBoard); });
      const r=account? await LB.rank(account.username,12):null;
      $('yourRank').textContent=(r&&r.rank)?('Your rank: #'+r.rank+' of '+r.of+' · last 12h'):'';
      return;
    }
  }
  renderLocalBoard();   // offline / server unreachable
}
$('boardBtn').onclick=openBoard;
// top-3 auto-shown on the home menu (online board, falling back to local accounts)
async function renderMenuTop3(){
  const list=$('menuBoardList'); if(!list) return;
  let rows=[];
  try{ if(LB.on()){ const data=await LB.board(12,3);
    if(data && data.leaderboard) rows=data.leaderboard.slice(0,3).map(p=>({n:p.username,w:p.wins,l:p.losses})); } }catch(e){}
  if(!rows.length) rows=Object.values(accounts()).sort((a,b)=>b.wins-a.wins||a.losses-b.losses)
    .filter(p=>(p.wins||0)+(p.losses||0)>0).slice(0,3).map(p=>({n:p.username,w:p.wins||0,l:p.losses||0}));
  if(!rows.length){ list.innerHTML='<div class="empty" style="padding:3px">No ranked games yet — be the first!</div>'; return; }
  const medal=['🥇','🥈','🥉'];
  list.innerHTML=rows.map((p,i)=>'<div class="mbrow"><span class="mbn">'+medal[i]+' '+p.n+'</span><span class="mbw">'+p.w+'W·'+p.l+'L</span></div>').join('');
}
