// ---- game flow ----
// ---- loading screen ("Bringing Goy into the system") + mode-entry banner ----
let _loadTimer=null, _bannerTimer=null;
function showLoadingThen(fn){
  const ov=$('loadingScreen');
  if(!ov){ fn&&fn(); return; }
  const pe=$('loadPepe'); if(pe && !pe.getAttribute('src')) pe.src=PEPE_SRC;   // spin Pepe
  ov.classList.remove('hide');
  clearTimeout(_loadTimer);
  _loadTimer=setTimeout(()=>{ ov.classList.add('hide'); fn&&fn(); }, 3500);
}
// ---- one-time session intro: terminal-typed text, then the black curtain rises to reveal an
// image for ~0.5s before continuing. Only fires on the FIRST START press of the session. ----
let introPlayed=false;
function showIntroLoading(fn){
  const ov=$('loadingScreen'), rev=$('introReveal'), lt=$('loadText'), pe=$('loadPepe');
  const haveImg = rev && $('introRevealImg') && ($('introRevealImg').getAttribute('src')||'').length>0;
  // if anything's missing (or no image embedded yet), fall back to the normal loader
  if(introPlayed || !ov || !lt || !haveImg){ showLoadingThen(fn); return; }
  introPlayed=true;
  rev.classList.remove('hide');                 // image waits behind the black panel
  ov.classList.remove('hide','rise'); ov.classList.add('intro');
  ov.style.transform='';
  if(pe) pe.style.display='none';               // pure terminal look during the intro
  const TYPE_MS=2300, RISE_MS=450, HOLD_MS=500;
  const msg='> based.cup booting…\n> escorting goyim into the system…';
  // single idempotent finish: tears everything down and continues. Tapping the screen skips
  // straight here, and a hard safety timer guarantees it ALWAYS runs even if timers are throttled
  // (e.g. the screen locks mid-intro) — so the loader can never trap the user on a black screen.
  let done=false;
  const finish=()=>{ if(done) return; done=true;
    clearTimeout(_loadTimer); clearTimeout(_introSafety);
    ov.removeEventListener('pointerdown',finish);
    ov.classList.add('hide'); ov.classList.remove('intro','rise'); ov.style.transform='';
    if(rev) rev.classList.add('hide'); if(pe) pe.style.display='';
    lt.classList.remove('typing');
    fn&&fn();
  };
  ov.addEventListener('pointerdown',finish);                 // tap anywhere to skip
  const _introSafety=setTimeout(finish, TYPE_MS+RISE_MS+HOLD_MS+2500);   // worst-case backstop
  lt.classList.add('typing'); lt.textContent='';
  const per=Math.max(18, TYPE_MS/msg.length); let i=0;
  clearTimeout(_loadTimer);
  (function tick(){
    if(done) return;
    if(i<=msg.length){ lt.textContent=msg.slice(0,i); i++; _loadTimer=setTimeout(tick, per); return; }
    lt.classList.remove('typing');                       // typing done (~1s before the end)
    _loadTimer=setTimeout(()=>{
      if(done) return;
      ov.classList.add('rise');                          // black curtain rises, uncovering the image
      _loadTimer=setTimeout(finish, RISE_MS+HOLD_MS);    // after the rise, hold the image then continue
    }, 120);
  })();
}
function showMatchBanner(){
  const b=$('matchBanner'); if(!b) return;
  $('mbMode').textContent = gameMode==='keepaway' ? '⏱️ KEEP-AWAY' : '⚽ GOALS';
  let vs;
  if(netRole) vs = 'vs '+(NET.peerName||'opponent');
  else if(mode==='2p') vs = '2 PLAYERS · local';
  else if(!oppActive) vs = 'SOLO practice';
  else vs = 'vs CPU';
  $('mbVs').textContent = vs;
  $('mbWager').textContent = (wager && wager.amount>0) ? ('💰 Wagering '+wager.amount+' $BASED') : '';
  b.classList.remove('hide');
  clearTimeout(_bannerTimer);
  _bannerTimer=setTimeout(()=>b.classList.add('hide'), 2000);
}

// touch devices get the on-screen joystick + KICK button (the #touch layer is display:none by default)
const IS_TOUCH = (typeof matchMedia==='function' && matchMedia('(pointer:coarse)').matches) || (typeof window!=='undefined' && 'ontouchstart' in window);
function enterMatchChrome(){
  $('xBtn').classList.add('hide');                          // X link off during a match (was overlapping the scorebug)
  $('touch').style.display = IS_TOUCH ? 'block' : 'none';   // show the joystick + KICK on phones
  document.body.classList.toggle('touch-match', IS_TOUCH);  // move player cards up top, free the bottom for thumbs
  const b = IS_TOUCH ? '156px' : '10px';                    // lift the pot/ping pills above the joystick on touch
  if($('potTag')) $('potTag').style.bottom=b; if($('pingTag')) $('pingTag').style.bottom=b;
  checkOrient();
}
// nudge phones into landscape during a match (the field is 1060x650 — portrait is unplayable).
// Menus stay usable in portrait; the hint only blocks once a game is actually being played.
function checkOrient(){
  const portrait = window.innerHeight > window.innerWidth;
  const playing = (state==='play' || state==='paused');
  document.body.classList.toggle('show-rotate', IS_TOUCH && portrait && playing);
}
addEventListener('resize', checkOrient);
addEventListener('orientationchange', ()=>setTimeout(checkOrient,150));
function beginGame(){ oppChar=null; showLoadingThen(_beginGame); }   // practice/local: opponent is the opposite character
function _beginGame(){
  ['authScreen','startScreen','winScreen','pauseScreen','matchScreen','selectScreen','socialScreen','boardScreen','profileScreen','inboxScreen']
    .forEach(s=>$(s).classList.add('hide'));
  $('acctBtn').classList.add('hide'); $('bellBtn').classList.add('hide');
  $('hud').classList.remove('hide'); $('liveCountHud').classList.remove('hide'); setMenuDocks(false);
  $('pCard').classList.remove('hide');
  $('tCard').classList.toggle('hide', !oppActive);
  $('pauseBtn').textContent='❚❚';
  enterMatchChrome();
  const oc = oppChar || (humanChar==='pepe'?'trumpe':'pepe');
  $('pCard').querySelector('.pc-name').textContent = account? account.username : STATS[humanChar].name;
  $('tCard').querySelector('.pc-name').textContent = ranked? 'CPU' : STATS[oc].name;
  $('pTeam').textContent = STATS[humanChar].abbr;
  $('tTeam').textContent = ranked? 'CPU' : STATS[oc].abbr;
  newGame(); lastTs=performance.now(); state='play'; audioInit(); stopMusic();
  showMatchBanner();
}
function togglePause(){
  if(netRole) return;   // can't pause a live online match
  if(state==='play'){ state='paused';
    $('pauseScreen').classList.remove('hide'); $('pauseBtn').textContent='▶'; }
  else if(state==='paused'){ state='play';
    $('pauseScreen').classList.add('hide'); $('pauseBtn').textContent='❚❚'; }
}
function gotoMenu(){
  if(netRole && NET.ws){ NET.intentionalClose=true; NET.send({t:'leave'}); try{NET.ws.close();}catch(e){} }
  NET.p2pReset();                            // tear down any direct connection so the next match renegotiates
  netRole=null; gp=null; resetWager(); oppChar=null;
  $('touch').style.display='none'; $('xBtn').classList.remove('hide');
  document.body.classList.remove('show-rotate'); document.body.classList.remove('touch-match');
  clearTimeout(htTimer); hideHalftime(); halftime=false;
  clearTimeout(_bannerTimer); $('matchBanner').classList.add('hide');
  clearTimeout(_loadTimer); $('loadingScreen').classList.add('hide');
  hideAllOverlays();
  ['hud','pCard','tCard','liveCountHud'].forEach(s=>$(s).classList.add('hide'));
  ranked=false; state='menu';
  $('startScreen').classList.remove('hide');
  const pt=$('pingTag'); if(pt)pt.classList.add('hide'); NET.rtt=null;
  refreshAcctBtn(); renderDaily(); syncRegionUI(); setMenuDocks(true); renderMenuTop3(); startMusic('lobby');
}
$('pauseBtn').onclick=togglePause;
$('muteBtn').onclick=toggleMute;
$('resumeBtn').onclick=togglePause;
$('pMenuBtn').onclick=gotoMenu;
// ---- end screen: online rematch handshake + leave detection ----
let rematchMe=false, rematchPeer=false, peerLeft=false;
function setupEndScreen(){
  rematchMe=false; rematchPeer=false; peerLeft=false;
  const rb=$('rematchBtn'); rb.classList.remove('disabled'); rb.textContent='REMATCH';
  $('rematchMsg').textContent = netRole ? 'Both players tap REMATCH to play again.' : '';
  const af=$('winAddFriend'); af.classList.remove('disabled');
  af.textContent = (netRole && NET.peerName) ? ('➕ ADD '+NET.peerName.toUpperCase()) : '➕ ADD FRIEND';
}
function greyRematch(msg){ const rb=$('rematchBtn'); rb.classList.add('disabled'); rb.textContent='REMATCH';
  $('rematchMsg').textContent=msg||''; }
function onPeerRematch(){ if(peerLeft) return; rematchPeer=true;
  $('rematchMsg').textContent = rematchMe ? 'Starting…' : 'Your friend wants a rematch!';
  if(rematchMe) doRematchStart(); }
function clickRematch(){
  if($('rematchBtn').classList.contains('disabled')) return;
  if(!netRole){ $('winScreen').classList.add('hide');
    showLoadingThen(()=>{ newGame(); lastTs=performance.now(); state='play'; showMatchBanner(); }); return; }
  if(peerLeft) return;
  rematchMe=true; $('rematchMsg').textContent = rematchPeer ? 'Starting…' : 'Waiting for your friend…';
  NET.relay({rematch:true});
  if(rematchPeer) doRematchStart();
}
function doRematchStart(){
  if(netRole==='host'){
    $('winScreen').classList.add('hide');
    sendHostStart();                  // guest gets d.start -> runs its own 3.5s loader via beginGameOnline
    showLoadingThen(()=>{ newGame(); lastTs=performance.now(); state='play'; showMatchBanner(); });
    rematchMe=false; rematchPeer=false;
  } else { $('rematchMsg').textContent='Starting…'; }   // guest waits for host's fresh start packet
}
$('rematchBtn').onclick=clickRematch;
$('menuBtn').onclick=()=>{ if(netRole){ try{ NET.relay({left:true}); }catch(e){} } gotoMenu(); };
$('winAddFriend').onclick=async ()=>{
  if(netRole && NET.peerName){
    await addFriend(NET.peerName);
    $('winAddFriend').textContent='REQUEST SENT'; $('winAddFriend').classList.add('disabled');
  } else openSocial();
};

